import{_ as t,c as s,o as a,a5 as n}from"./chunks/framework.CgT1UzWm.js";const g=JSON.parse('{"title":"Django — PostgreSQL REST API Benchmark, July 2026","titleTemplate":"NpgsqlRest","description":"Django 6.0.7 in the July 2026 PostgreSQL REST API benchmark: last in most categories, a surprising #4 in nested JSON and heavy payloads, and finally measured on equal terms.","frontmatter":{"layout":"doc","outline":[2,3],"title":"Django — PostgreSQL REST API Benchmark, July 2026","titleTemplate":"NpgsqlRest","description":"Django 6.0.7 in the July 2026 PostgreSQL REST API benchmark: last in most categories, a surprising #4 in nested JSON and heavy payloads, and finally measured on equal terms.","head":[["link",{"rel":"canonical","href":"https://npgsqlrest.github.io/blog/benchmarks-2026-07/django.html"}],["meta",{"property":"og:url","content":"https://npgsqlrest.github.io/blog/benchmarks-2026-07/django.html"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:title","content":"Django — PostgreSQL REST API Benchmark, July 2026"}],["meta",{"property":"og:description","content":"Django 6.0.7 in the July 2026 PostgreSQL REST API benchmark: last in most categories, a surprising #4 in nested JSON and heavy payloads, and finally measured on equal terms."}],["meta",{"property":"og:image","content":"https://npgsqlrest.github.io/og-image.png"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Django — PostgreSQL REST API Benchmark, July 2026"}],["meta",{"name":"twitter:description","content":"Django 6.0.7 in the July 2026 PostgreSQL REST API benchmark: last in most categories, a surprising #4 in nested JSON and heavy payloads, and finally measured on equal terms."}],["meta",{"name":"twitter:image","content":"https://npgsqlrest.github.io/og-image.png"}]]},"headers":[],"relativePath":"blog/benchmarks-2026-07/django.md","filePath":"blog/benchmarks-2026-07/django.md","lastUpdated":1782480183000}'),r={name:"blog/benchmarks-2026-07/django.md"};function i(o,e,l,h,d,p){return a(),s("div",null,e[0]||(e[0]=[n(`<h1 id="django-6-0-7-gunicorn-psycopg-3" tabindex="-1">Django 6.0.7 (gunicorn + psycopg 3) <a class="header-anchor" href="#django-6-0-7-gunicorn-psycopg-3" aria-label="Permalink to &quot;Django 6.0.7 (gunicorn + psycopg 3)&quot;">​</a></h1><p class="blog-meta"><span class="tag">Benchmark</span> · <span class="tag">Python</span> · <span class="tag">July 2026</span></p><p>Part of the <a href="/blog/benchmarks-2026-07/">PostgreSQL REST API Benchmark, July 2026</a> series.</p><h2 id="at-a-glance" tabindex="-1">At a glance <a class="header-anchor" href="#at-a-glance" aria-label="Permalink to &quot;At a glance&quot;">​</a></h2><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>Version</strong></td><td>Django 6.0.7 on Python 3.14, gunicorn 26 with uvicorn workers (ASGI)</td></tr><tr><td><strong>PostgreSQL driver</strong></td><td>psycopg 3.3.4 with <code>psycopg_pool</code> — 8 workers × 12 connections ≈ 100 aggregate</td></tr><tr><td><strong>Concurrency model</strong></td><td>Synchronous views, one gunicorn worker per core (<code>-w $(nproc)</code>)</td></tr><tr><td><strong>Lines of code</strong></td><td>183</td></tr><tr><td><strong>Podiums</strong></td><td>none — 0 of 38 combinations</td></tr><tr><td><strong>Source</strong></td><td><a href="https://github.com/NpgsqlRest/pg_function_load_tests/tree/202607131327/src/django-app-v6.0.7" target="_blank" rel="noreferrer">django-app-v6.0.7</a></td></tr></tbody></table></div></div><p><strong>The verdict in one sentence: you don&#39;t pick Django for req/s — but measured on equal terms it is no longer an outlier, and in the payload-heavy combinations it is genuinely good.</strong></p><h2 id="implementation" tabindex="-1">Implementation <a class="header-anchor" href="#implementation" aria-label="Permalink to &quot;Implementation&quot;">​</a></h2><p>Plain synchronous views with raw cursors (<a href="https://github.com/NpgsqlRest/pg_function_load_tests/blob/202607131327/src/django-app-v6.0.7/app/views.py" target="_blank" rel="noreferrer">views.py</a>) — no ORM models, no middleware (<code>MIDDLEWARE = []</code>), a single installed app. The fairness-relevant change lives in <a href="https://github.com/NpgsqlRest/pg_function_load_tests/blob/202607131327/src/django-app-v6.0.7/app/settings.py" target="_blank" rel="noreferrer">settings.py</a>:</p><details class="code-collapsible" open><summary>python</summary><div class="language-python vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;OPTIONS&#39;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> {</span></span>
<span class="line"><span style="--shiki-light:#9CA0B0;--shiki-light-font-style:italic;--shiki-dark:#6C7086;--shiki-dark-font-style:italic;">    # Pool is per gunicorn worker; workers x max_size ~= 100 aggregate</span></span>
<span class="line"><span style="--shiki-light:#9CA0B0;--shiki-light-font-style:italic;--shiki-dark:#6C7086;--shiki-dark-font-style:italic;">    # to match the single-pool services (psycopg_pool default max is only 4).</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">    &#39;pool&#39;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;"> {</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;min_size&#39;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#FE640B;--shiki-dark:#FAB387;"> 2</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">,</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> &#39;max_size&#39;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">:</span><span style="--shiki-light:#FE640B;--shiki-light-font-style:italic;--shiki-dark:#FAB387;--shiki-dark-font-style:italic;"> int</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">(</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">os</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">.</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">getenv</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">(</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;POOL_MAX_SIZE&#39;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">,</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> &#39;12&#39;</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">))},</span></span>
<span class="line"><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">},</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div></details><details class="code-collapsible" open><summary>dockerfile</summary><div class="language-dockerfile vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">dockerfile</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">CMD</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> gunicorn app.asgi:application -k uvicorn.workers.UvicornWorker \\</span></span>
<span class="line"><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">    -w \${WORKERS:-$(nproc)} -b 0.0.0.0:8000 --log-level warning</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div></details><p>In January, Django ran 4 workers on psycopg&#39;s default pool of 4 connections each. Note this is already a stripped-down Django — a production deployment with sessions, auth, and a middleware stack would sit below every number on this page.</p><h2 id="results" tabindex="-1">Results <a class="header-anchor" href="#results" aria-label="Permalink to &quot;Results&quot;">​</a></h2><h3 id="the-floor" tabindex="-1">The floor <a class="header-anchor" href="#the-floor" aria-label="Permalink to &quot;The floor&quot;">​</a></h3><p>Wherever the request itself is the work, Django is last of 20 — at every concurrency level:</p><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Scenario</th><th>Result</th></tr></thead><tbody><tr><td>Minimal baseline</td><td>2,601 req/s at 100 VU (#20) — the only service below 6,000; the leader (Go) is 6.5× ahead</td></tr><tr><td>Many parameters</td><td>2,411 req/s at 50 VU (#20)</td></tr><tr><td>POST, 10 records</td><td>2,492 req/s at 50 VU (#20)</td></tr><tr><td>perf-test, 1 record</td><td>358 req/s at 1 VU (#20); 2,005 at 50 VU (#19), ahead of only PostgREST</td></tr></tbody></table></div></div><p>The pattern is uniform: routing, request-object construction, and Python-side value conversion put a hard per-request ceiling of roughly 2,000–2,600 req/s on four cores, regardless of scenario.</p><h3 id="the-bright-spots" tabindex="-1">The bright spots <a class="header-anchor" href="#the-bright-spots" aria-label="Permalink to &quot;The bright spots&quot;">​</a></h3><p>Two results break the caricature. First, <strong>nested JSON: #4 of 20 in all six combinations</strong> — 1,963 / 1,900 / 1,869 req/s at 50 VU across depths 1–3 — behind only Go, Swoole, and FastAPI, and ahead of both Rust frameworks and every Node runtime. Its depth penalty (−4.8% from depth 1 to 3) is the smallest in the field, better even than Go&#39;s −6.4%: <code>JsonResponse</code> passes PostgreSQL&#39;s pre-serialized JSON through without reprocessing.</p><p>Second, the heavy perf-test combinations, where payload dwarfs per-request overhead:</p><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>perf-test</th><th style="text-align:right;">50 VU</th><th style="text-align:right;">100 VU</th><th style="text-align:right;">200 VU</th></tr></thead><tbody><tr><td>100 records</td><td style="text-align:right;">174 (#4)</td><td style="text-align:right;">173 (#4)</td><td style="text-align:right;">171 (#4)</td></tr><tr><td>500 records</td><td style="text-align:right;">37 (#4)</td><td style="text-align:right;">36 (#4)</td><td style="text-align:right;">36 (#4)</td></tr></tbody></table></div></div><p>Again #4, behind only Swoole, Go, and FastAPI. Add 100-record POST (#6, 1,284 req/s at 50 VU) and 500 KB payloads (#5, 322–327 req/s) and a consistent picture emerges: when the database does the work, Django keeps pace with the top quartile.</p><h3 id="latency" tabindex="-1">Latency <a class="header-anchor" href="#latency" aria-label="Permalink to &quot;Latency&quot;">​</a></h3><p>The per-request ceiling shows up as the field&#39;s worst small-request tails: p99 of 82 ms on the minimal baseline at 100 VU, where the leaders sit at 21–23 ms, and 5 ms at 1 VU where the field posts 2–3 ms. In its strong combinations the picture inverts — 57 ms p99 on nested depth 1 at 50 VU is fourth-best, and its heavy perf-test tails track the leaders.</p><h2 id="resource-usage" tabindex="-1">Resource usage <a class="header-anchor" href="#resource-usage" aria-label="Permalink to &quot;Resource usage&quot;">​</a></h2><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th style="text-align:right;">Peak memory</th><th style="text-align:right;">Avg memory</th><th style="text-align:right;">Avg CPU</th></tr></thead><tbody><tr><td style="text-align:right;">671 MB</td><td style="text-align:right;">281 MB</td><td style="text-align:right;"><strong>229.6%</strong></td></tr></tbody></table></div></div><p>The highest average CPU of all 20 services — more than Go and Swoole combined and change — and the third-highest peak memory, though still well under the Node cluster deployments (Express 1,094 MB, Fastify 1,177 MB). Django works hard for its numbers.</p><h2 id="analysis" tabindex="-1">Analysis <a class="header-anchor" href="#analysis" aria-label="Permalink to &quot;Analysis&quot;">​</a></h2><p>The point of including Django was never to watch it win; it was to measure what a full-featured, batteries-included framework actually costs when everything around it is fair. January&#39;s setup — 4 workers, 4-connection default pools — understated it; this round&#39;s 8 workers × 12 connections is a configuration Django&#39;s own documentation would endorse. On those terms, ~2,400 req/s on trivial endpoints is the honest price of the framework, and #4 in the field on payload-heavy work is the honest reward: Django&#39;s overhead is per-request, not per-byte.</p><p>The fair conclusion cuts both ways. If your API&#39;s job is high-frequency small requests, Django costs you roughly 5× the throughput of the mid-field at maximum CPU burn. If your API returns real result sets — reports, nested documents, wide rows — the gap to the leaders shrinks to 15–20%, and everything Django ships in the box comes essentially free.</p><p><strong>January → July movement:</strong> still last or near-last in the server-bound categories, exactly as in January — the pool fix raised its ceiling, not its rank. The heavy-payload #4 placements are where equal pooling finally let it show something. Rankings only — the methodology changed too much for absolute comparisons.</p><h2 id="explore-on-github" tabindex="-1">Explore on GitHub <a class="header-anchor" href="#explore-on-github" aria-label="Permalink to &quot;Explore on GitHub&quot;">​</a></h2><p>Everything this page claims can be checked against the running code and the raw output:</p><ul><li><a href="https://github.com/NpgsqlRest/pg_function_load_tests/tree/202607131327/src/django-app-v6.0.7" target="_blank" rel="noreferrer">Application source</a></li><li><a href="https://github.com/NpgsqlRest/pg_function_load_tests/blob/202607131327/src/_postgres/init.sql" target="_blank" rel="noreferrer">The PostgreSQL functions every service calls</a></li><li><a href="https://github.com/NpgsqlRest/pg_function_load_tests/tree/202607131327/src/_k6/scripts" target="_blank" rel="noreferrer">k6 load scripts</a></li><li><a href="https://github.com/NpgsqlRest/pg_function_load_tests/tree/202607131327/src/_k6/results/202607131327" target="_blank" rel="noreferrer">This run&#39;s per-test k6 summaries</a> — filter by this service&#39;s name</li><li><a href="https://github.com/NpgsqlRest/pg_function_load_tests/blob/202607131327/src/_k6/results/202607131327/results.csv" target="_blank" rel="noreferrer">Complete dataset: results.csv</a></li></ul><hr><p><strong>Series:</strong> <a href="/blog/benchmarks-2026-07/">Introduction</a> · <a href="/blog/benchmarks-2026-07/analysis.html">Overall Analysis</a> · <a href="/blog/benchmarks-2026-07/results.html">Raw Results</a></p><p><strong>Next framework:</strong> <a href="/blog/benchmarks-2026-07/fastify.html">Fastify →</a></p>`,36)]))}const u=t(r,[["render",i]]);export{g as __pageData,u as default};
